159→    font-weight: 600;
160→    color: var(--text-secondary, #6b7280);
161→    text-transform: uppercase;
162→    letter-spacing: 0.4px;
163→    margin: 0;
164→}
165→
166→.analytics-chart-container {
167→    width: 100%;
168→    min-height: 220px;
169→}
170→
171→/* ─── Chart Tooltip ─── */
172→
173→.analytics-chart-tooltip {
